import { buildAnalytics } from '../analytics/usageAnalytics';
import { APP_VERSION, DEFAULT_PREFERENCES, HISTORY_LIMIT, PREFERENCES_SYNC_KEY, STATE_KEY } from '../lib/constants';
import type { AppSnapshot, PersistedState, Preferences, SiteId, SiteSessionState, ThreadSnapshot, UsageEvent } from '../types';

const memoryStorage = new Map<string, unknown>();
let writeQueue: Promise<unknown> = Promise.resolve();

function localArea() {
  return chrome?.storage?.local;
}

function syncArea() {
  return chrome?.storage?.sync;
}

async function storageGet<T>(key: string): Promise<T | undefined> {
  const area = localArea();
  if (area) {
    const result = await area.get(key);
    return result[key] as T | undefined;
  }
  return memoryStorage.get(key) as T | undefined;
}

async function storageSet(value: Record<string, unknown>): Promise<void> {
  const area = localArea();
  if (area) {
    await area.set(value);
    return;
  }
  for (const [key, entry] of Object.entries(value)) {
    memoryStorage.set(key, entry);
  }
}

function defaultPromptAnalysis() {
  return {
    inputTokens: 0,
    outputTokensEstimate: 0,
    totalTokens: 0,
    sections: [],
    suggestions: [],
    variants: {
      shorter: '',
      balanced: '',
      maxDetail: ''
    },
    repeatedInstructions: [],
    redundantSections: [],
    largePaste: false,
    compressionScore: 0
  };
}

function defaultQuotaStatus() {
  return {
    usedTokens: 0,
    status: 'unknown' as const,
    accuracy: 'inferred' as const
  };
}

function mergePreferences(partial?: Preferences): Preferences {
  return {
    ...DEFAULT_PREFERENCES,
    ...partial,
    alerts: {
      ...DEFAULT_PREFERENCES.alerts,
      ...(partial?.alerts ?? {})
    },
    sites: {
      ...DEFAULT_PREFERENCES.sites,
      ...(partial?.sites ?? {})
    }
  };
}

function hydrateState(raw?: PersistedState): PersistedState {
  return {
    version: APP_VERSION,
    preferences: mergePreferences(raw?.preferences),
    sessions: raw?.sessions ?? {
      chatgpt: undefined,
      claude: undefined,
      gemini: undefined,
      perplexity: undefined,
      grok: undefined,
      generic: undefined
    },
    usageEvents: raw?.usageEvents ?? [],
    threads: raw?.threads ?? {},
    meta: raw?.meta ?? { notificationTimestamps: {} }
  };
}

export async function getState(): Promise<PersistedState> {
  const rawState = await storageGet<PersistedState>(STATE_KEY);
  let state = hydrateState(rawState);

  let syncedPreferences: Preferences | undefined;
  const sync = syncArea();
  if (sync) {
    try {
      const result = await sync.get(PREFERENCES_SYNC_KEY);
      syncedPreferences = result[PREFERENCES_SYNC_KEY] as Preferences | undefined;
    } catch {
      syncedPreferences = undefined;
    }
  }
  if (syncedPreferences && state.preferences.privacyMode === 'sync-preferences') {
    state = {
      ...state,
      preferences: mergePreferences(syncedPreferences)
    };
  }

  return state;
}

export async function saveState(state: PersistedState): Promise<PersistedState> {
  const hydrated = hydrateState(state);
  await storageSet({ [STATE_KEY]: hydrated });
  if (hydrated.preferences.privacyMode === 'sync-preferences') {
    await syncArea()?.set({ [PREFERENCES_SYNC_KEY]: hydrated.preferences }).catch(() => undefined);
  }
  return hydrated;
}

export async function updateState(mutator: (state: PersistedState) => PersistedState | Promise<PersistedState>): Promise<PersistedState> {
  writeQueue = writeQueue.then(async () => {
    const current = await getState();
    const next = await mutator(structuredClone(current));
    return saveState(next);
  });
  return writeQueue as Promise<PersistedState>;
}

export async function savePreferences(preferences: Preferences): Promise<PersistedState> {
  return updateState(async (state) => ({
    ...state,
    preferences: mergePreferences(preferences)
  }));
}

export async function saveSession(session: SiteSessionState): Promise<PersistedState> {
  return updateState(async (state) => ({
    ...state,
    sessions: {
      ...state.sessions,
      [session.site]: {
        ...session,
        currentEstimate: session.currentEstimate ?? defaultPromptAnalysis(),
        quota: session.quota ?? defaultQuotaStatus()
      }
    }
  }));
}

function threadKey(site: SiteId, threadId: string): string {
  return `${site}:${threadId || 'default'}`;
}

function upsertThread(threads: Record<string, ThreadSnapshot>, event: UsageEvent): Record<string, ThreadSnapshot> {
  const key = threadKey(event.site, event.threadId);
  const existing = threads[key] ?? {
    threadId: event.threadId,
    site: event.site,
    model: event.model,
    messageCount: 0,
    promptTokens: 0,
    outputTokens: 0,
    totalTokens: 0,
    lastUpdated: event.timestamp,
    contextGrowth: []
  };

  const totalTokens = existing.totalTokens + event.totalTokens;
  return {
    ...threads,
    [key]: {
      ...existing,
      model: event.model,
      messageCount: existing.messageCount + 2,
      promptTokens: existing.promptTokens + event.promptTokens,
      outputTokens: existing.outputTokens + event.outputTokens,
      totalTokens,
      lastUpdated: event.timestamp,
      contextGrowth: [...existing.contextGrowth.slice(-24), totalTokens]
    }
  };
}

export async function recordUsageEvent(event: UsageEvent): Promise<PersistedState> {
  return updateState(async (state) => ({
    ...state,
    usageEvents: [...state.usageEvents, event].slice(-HISTORY_LIMIT),
    threads: upsertThread(state.threads, event)
  }));
}

export function buildSnapshot(state: PersistedState, activeUrl?: string): AppSnapshot {
  const analytics = buildAnalytics(state.usageEvents, state.preferences);
  const sessions = Object.values(state.sessions)
    .filter((session): session is SiteSessionState => Boolean(session))
    .sort((a, b) => b.lastUpdated - a.lastUpdated);

  const currentSession = (() => {
    if (!activeUrl) return sessions[0];
    try {
      const hostname = new URL(activeUrl).hostname;
      return sessions.find((session) => session.lastSeenUrl.includes(hostname)) ?? sessions[0];
    } catch {
      return sessions[0];
    }
  })();

  const today = analytics.byDay.at(-1);
  const tokensThisWeek = analytics.byDay.slice(-7).reduce((acc, day) => acc + day.tokens, 0);
  const costThisWeek = analytics.byDay.slice(-7).reduce((acc, day) => acc + day.cost, 0);

  return {
    state,
    analytics,
    summary: {
      tokensToday: today?.tokens ?? 0,
      tokensThisWeek,
      costThisWeek,
      activeSites: analytics.bySite.length,
      promptsToday: today?.prompts ?? 0
    },
    currentSession,
    sessions,
    recentThreads: Object.values(state.threads).sort((a, b) => b.lastUpdated - a.lastUpdated).slice(0, 10),
    generatedAt: Date.now()
  };
}

export async function exportState(): Promise<PersistedState> {
  return getState();
}

export async function importState(state: PersistedState): Promise<PersistedState> {
  return saveState(hydrateState(state));
}
