import type { AnalyticsSnapshot, BreakdownMetric, DailyMetric, Preferences, UsageEvent } from '../types';
import { MODEL_CATALOG, SITE_LABELS } from '../lib/constants';
import { average, groupBy, startOfLocalDay, startOfLocalWeek, toDateKey } from '../lib/utils';

function eventCost(event: UsageEvent, preferences: Preferences): number {
  const siteSettings = preferences.sites[event.site];
  const modelProfile = MODEL_CATALOG[event.model] ?? MODEL_CATALOG.generic;
  const inputRate = siteSettings.costInputPer1k ?? modelProfile.estimatedInputCostPer1k ?? 0;
  const outputRate = siteSettings.costOutputPer1k ?? modelProfile.estimatedOutputCostPer1k ?? 0;
  return (event.promptTokens / 1000) * inputRate + (event.outputTokens / 1000) * outputRate;
}

function fillWindow(start: number, count: number, stepMs: number, values: Map<string, DailyMetric>): DailyMetric[] {
  return Array.from({ length: count }, (_, index) => {
    const timestamp = start + index * stepMs;
    const key = toDateKey(timestamp);
    return values.get(key) ?? { date: key, tokens: 0, prompts: 0, cost: 0 };
  });
}

function aggregateBy<T extends string>(events: UsageEvent[], keyFn: (event: UsageEvent) => T, preferences: Preferences, labelFn: (key: T) => string): BreakdownMetric[] {
  const groups = groupBy(events, keyFn);
  return Object.entries(groups)
    .map(([key, group]) => {
      const entries = group as UsageEvent[];
      return {
        id: key,
        label: labelFn(key as T),
        tokens: entries.reduce((acc, event) => acc + event.totalTokens, 0),
        prompts: entries.length,
        cost: entries.reduce((acc, event) => acc + eventCost(event, preferences), 0)
      };
    })
    .sort((a, b) => b.tokens - a.tokens);
}

function calculateStreak(events: UsageEvent[]): number {
  if (!events.length) return 0;
  const usedDays = new Set(events.map((event) => startOfLocalDay(event.timestamp)));
  let streak = 0;
  let cursor = startOfLocalDay(Date.now());
  while (usedDays.has(cursor)) {
    streak += 1;
    cursor -= 86_400_000;
  }
  return streak;
}

export function buildAnalytics(events: UsageEvent[], preferences: Preferences): AnalyticsSnapshot {
  const sorted = [...events].sort((a, b) => a.timestamp - b.timestamp);
  const now = Date.now();
  const fourteenDaysAgo = startOfLocalDay(now - 13 * 86_400_000);
  const eightWeeksAgo = startOfLocalWeek(now - 7 * 7 * 86_400_000);

  const dayMap = new Map<string, DailyMetric>();
  const weekMap = new Map<string, DailyMetric>();

  for (const event of sorted) {
    const dayKey = toDateKey(event.timestamp);
    const dayMetric = dayMap.get(dayKey) ?? { date: dayKey, tokens: 0, prompts: 0, cost: 0 };
    dayMetric.tokens += event.totalTokens;
    dayMetric.prompts += 1;
    dayMetric.cost += eventCost(event, preferences);
    dayMap.set(dayKey, dayMetric);

    const weekStart = startOfLocalWeek(event.timestamp);
    const weekKey = toDateKey(weekStart);
    const weekMetric = weekMap.get(weekKey) ?? { date: weekKey, tokens: 0, prompts: 0, cost: 0 };
    weekMetric.tokens += event.totalTokens;
    weekMetric.prompts += 1;
    weekMetric.cost += eventCost(event, preferences);
    weekMap.set(weekKey, weekMetric);
  }

  const byDay = fillWindow(fourteenDaysAgo, 14, 86_400_000, dayMap);
  const byWeek = fillWindow(eightWeeksAgo, 8, 7 * 86_400_000, weekMap);
  const byModel = aggregateBy(sorted, (event) => event.model, preferences, (key) => MODEL_CATALOG[key]?.label ?? key);
  const bySite = aggregateBy(sorted, (event) => event.site, preferences, (key) => SITE_LABELS[key] ?? key);
  const peakDay = [...byDay].sort((a, b) => b.tokens - a.tokens)[0];
  const averagePromptTokens = average(sorted.map((event) => event.promptTokens));
  const lastSevenDays = byDay.slice(-7);
  const burnRate = average(lastSevenDays.map((day) => day.tokens));
  const baseline = average(sorted.map((event) => event.totalTokens));
  const anomalyThreshold = baseline * preferences.alerts.anomalyMultiplier;
  const anomalies = sorted.filter((event) => event.totalTokens >= Math.max(anomalyThreshold, preferences.alerts.largePromptTokens)).slice(-25).reverse();

  return {
    byDay,
    byWeek,
    byModel,
    bySite,
    burnRate,
    averagePromptTokens,
    peakDay,
    streakDays: calculateStreak(sorted),
    anomalies,
    timeline: sorted.slice(-60).reverse()
  };
}
