import { DEFAULT_PREFERENCES, SITE_LABELS } from '../lib/constants';
import { formatPercent, formatTokens } from '../lib/format';
import type { RuntimeRequest } from '../lib/runtime';
import { buildSnapshot, exportState, getState, importState, recordUsageEvent, savePreferences, saveSession } from '../storage/store';
import type { PersistedState, SiteSessionState, UsageEvent } from '../types';

const ALARM_NAME = 'yor-token-usage-refresh';

async function ensureState(): Promise<PersistedState> {
  const state = await getState();
  if (!state.preferences) {
    await savePreferences(DEFAULT_PREFERENCES);
  }
  return state;
}

async function withNotificationBudget(key: string, ttlMs: number, task: () => Promise<void>): Promise<void> {
  const state = await getState();
  const lastSent = state.meta.notificationTimestamps[key] ?? 0;
  if (Date.now() - lastSent < ttlMs) return;
  await task();
  await importState({
    ...state,
    meta: {
      ...state.meta,
      notificationTimestamps: {
        ...state.meta.notificationTimestamps,
        [key]: Date.now()
      }
    }
  });
}

async function notify(title: string, message: string): Promise<void> {
  await chrome.notifications.create({
    type: 'basic',
    iconUrl: 'assets/icons/icon-128.png',
    title,
    message
  });
}

async function updateBadge(session?: SiteSessionState): Promise<void> {
  const state = await getState();
  const target = session ?? Object.values(state.sessions).filter(Boolean).sort((a, b) => (b?.lastUpdated ?? 0) - (a?.lastUpdated ?? 0))[0];
  if (!target || state.preferences.alerts.badgeMode === 'off') {
    await chrome.action.setBadgeText({ text: '' });
    return;
  }

  const badgeText = state.preferences.alerts.badgeMode === 'remaining'
    ? formatTokens(target.quota.remainingTokens).replace(/\.0K$/, 'K')
    : formatPercent(target.quota.percentUsed).replace('%', '');

  await chrome.action.setBadgeText({ text: badgeText === '—' ? '' : badgeText.slice(0, 4) });
  await chrome.action.setBadgeBackgroundColor({
    color: target.quota.status === 'limited' ? '#ff5f6d' : target.quota.status === 'warning' ? '#ffb84d' : '#6d8dff'
  });
}

async function notifyIfNeededFromSession(session: SiteSessionState): Promise<void> {
  const preferences = (await getState()).preferences;
  if (!preferences.alerts.desktopNotifications) return;
  const threshold = preferences.alerts.quotaWarningPercent;

  if (session.quota.percentUsed !== undefined && session.quota.percentUsed >= threshold) {
    await withNotificationBudget(`quota:${session.site}:${session.model}`, 45 * 60_000, async () => {
      await notify(
        `${SITE_LABELS[session.site]} quota warning`,
        `${session.model} is at ${formatPercent(session.quota.percentUsed)}. Reset ${session.quota.nextReset?.localLabel ?? 'unknown'}.`
      );
    });
  }
}

async function notifyIfNeededFromEvent(event: UsageEvent): Promise<void> {
  const state = await getState();
  if (!state.preferences.alerts.desktopNotifications) return;

  if (event.totalTokens >= state.preferences.alerts.largePromptTokens) {
    await withNotificationBudget(`event:${event.id}`, 12 * 60_000, async () => {
      await notify('Large prompt detected', `That exchange used about ${formatTokens(event.totalTokens)} tokens.`);
    });
  }

  if (event.status === 'rate_limited') {
    await withNotificationBudget(`limit:${event.site}:${event.resetAt ?? 'unknown'}`, 30 * 60_000, async () => {
      await notify(
        `${SITE_LABELS[event.site]} limit reached`,
        event.rateLimitMessage ?? `The site signaled a usage limit. Reset ${event.resetAt ? 'around ' + new Date(event.resetAt).toLocaleTimeString() : 'time is not known yet'}.`
      );
    });
  }
}

chrome.runtime.onInstalled.addListener(async () => {
  await ensureState();
  chrome.alarms.create(ALARM_NAME, { periodInMinutes: 5 });
  await updateBadge();
});

chrome.runtime.onStartup.addListener(async () => {
  await ensureState();
  chrome.alarms.create(ALARM_NAME, { periodInMinutes: 5 });
  await updateBadge();
});

chrome.alarms.onAlarm.addListener(async (alarm) => {
  if (alarm.name !== ALARM_NAME) return;
  const state = await getState();
  const sessions = Object.values(state.sessions).filter((session): session is SiteSessionState => Boolean(session));
  for (const session of sessions) {
    await notifyIfNeededFromSession(session);
  }
  await updateBadge();
});

chrome.commands.onCommand.addListener(async (command) => {
  if (command === 'open-dashboard') {
    await chrome.tabs.create({ url: chrome.runtime.getURL('dashboard/dashboard.html') });
    return;
  }
  if (command === 'toggle-overlay') {
    const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });
    if (tab?.id) {
      await chrome.tabs.sendMessage(tab.id, { type: 'toggle-overlay' }).catch(() => undefined);
    }
  }
});

chrome.runtime.onMessage.addListener((message: RuntimeRequest, _sender, sendResponse) => {
  void (async () => {
    switch (message.type) {
      case 'capture-session': {
        const state = await saveSession(message.payload);
        await updateBadge(message.payload);
        await notifyIfNeededFromSession(message.payload);
        sendResponse({ ok: true, snapshot: buildSnapshot(state) });
        break;
      }
      case 'commit-usage-event': {
        const state = await recordUsageEvent(message.payload);
        await updateBadge();
        await notifyIfNeededFromEvent(message.payload);
        sendResponse({ ok: true, snapshot: buildSnapshot(state) });
        break;
      }
      case 'get-snapshot': {
        const state = await getState();
        sendResponse(buildSnapshot(state, message.activeUrl));
        break;
      }
      case 'get-state': {
        sendResponse(await getState());
        break;
      }
      case 'save-preferences': {
        const state = await savePreferences(message.payload);
        await updateBadge();
        sendResponse(buildSnapshot(state));
        break;
      }
      case 'export-data': {
        sendResponse(await exportState());
        break;
      }
      case 'import-data': {
        const state = await importState(message.payload);
        await updateBadge();
        sendResponse(buildSnapshot(state));
        break;
      }
      case 'toggle-overlay': {
        const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });
        if (tab?.id) {
          const result = await chrome.tabs.sendMessage(tab.id, { type: 'toggle-overlay', value: message.value }).catch(() => undefined);
          sendResponse(result ?? { ok: false });
        } else {
          sendResponse({ ok: false });
        }
        break;
      }
      case 'notify': {
        await notify(message.title, message.message);
        sendResponse({ ok: true });
        break;
      }
      default:
        sendResponse({ ok: false });
    }
  })();
  return true;
});
